def assess(record: dict) -> str:
    required = {"case_id", "use", "out_of_scope", "contestability"}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    if record.get("use") == "fraud_label" or "fraud_label" not in (record.get("out_of_scope") or []):
        # valid: use queue_rank, out_of_scope includes fraud_label, contestability True
        pass
    ok = (
        record.get("use") == "queue_rank"
        and "fraud_label" in (record.get("out_of_scope") or [])
        and record.get("contestability") is True
    )
    return "PASS" if ok else "REJECT_SCOPE_BREACH"

